var InkWeb = {

  version: 0.04,

  NS: {
    svg:      "http://www.w3.org/2000/svg",
    sodipodi: "http://sodipodi.sourceforge.net/DTD/sodipodi-0.dtd",
    inkscape: "http://www.inkscape.org/namespaces/inkscape",
    cc:       "http://creativecommons.org/ns#",
    dc:       "http://purl.org/dc/elements/1.1/",
    rdf:      "http://www.w3.org/1999/02/22-rdf-syntax-ns#",
    xlink:    "http://www.w3.org/1999/xlink",
    xml:      "http://www.w3.org/XML/1998/namespace"
  }

};

InkWeb.el = function (tag, attributes) {
  // A helper to create SVG elements
  var element = document.createElementNS( this.NS.svg, tag );
  for ( var att in attributes ) {
    switch ( att ) {
      case "parent":
        attributes.parent.appendChild( element );
        break;
      case "text":
        element.appendChild( document.createTextNode( attributes.text ) );
        break;
      default:
        element.setAttribute( att, attributes[att] );
    }
  }
  return element;
}

InkWeb.reGetStyleAttVal = function (att) {
  return new RegExp( "(^|.*;)[ ]*"+ att +":([^;]*)(;.*|$)" )
}

InkWeb.getStyle = function (el, att) {
  // This method is needed because el.style is only working
  // to HTML style in the Firefox 3.0
  if ( typeof(el) == "string" )
    el = Nayad.safeGetElement(el);
  var style = el.getAttribute("style");
  var match = this.reGetStyleAttVal(att).exec(style);
  if ( match ) {
    return match[2];
  } else {
    return false;
  }
}

InkWeb.setStyle = function (el, att, val) {
  if ( typeof(el) == "string" )
    el = Nayad.safeGetElement(el);
  var style = el.getAttribute("style");
  re = this.reGetStyleAttVal(att);
  if ( re.test(style) ) {
    style = style.replace( re, "$1"+ att +":"+ val +"$3" );
  } else {
    style += ";"+ att +":"+ val;
  }
  el.setAttribute( "style", style );
  return val
}

InkWeb.transmitAtt = function (conf) {
  conf.att = conf.att.split( /\s+/ );
  if ( typeof(conf.from) == "string" )
    conf.from = Nayad.safeGetElement( conf.from );
  if ( ! conf.to.join )
    conf.to = [ conf.to ];
  for ( var toEl,elN=0; toEl=conf.to[elN]; elN++ ) {
    if ( typeof(toEl) == "string" )
      toEl = Nayad.safeGetElement( toEl );
    for ( var i=0; i<conf.att.length; i++ ) {
      var val = this.getStyle( conf.from, conf.att[i] );
      if ( val ) {
        this.setStyle( toEl, conf.att[i], val );
      } else {
        val = conf.from.getAttribute(conf.att[i]);
        toEl.setAttribute( conf.att[i], val );
      }
    }
  }
}

InkWeb.setAtt = function (conf) {
  if ( ! conf.el.join )
    conf.to = [ conf.el ];
  conf.att = conf.att.split( /\s+/ );
  conf.val = conf.val.split( /\s+/ );
  for ( var el,elN=0; el=conf.el[elN]; elN++ ) {
    if ( typeof(el) == "string" )
      el = Nayad.safeGetElement( el );
    for ( var att,i=0; att=conf.att[i]; i++ ) {
      if (
           att == "width"  ||
           att == "height" ||
           att == "x"  ||
           att == "y"  ||
           att == "cx" ||
           att == "cy" ||
           att == "r"  ||
           att == "rx" ||
           att == "ry" ||
           att == "transform"
         ) {
        el.setAttribute( att, conf.val[i] );
      } else {
        this.setStyle( el, att, conf.val[i] );
      }
    }
  }
}

InkWeb.moveElTo = function (startConf) {
  if ( typeof(startConf) == "string" ) {
    // startConf may be only a element Id, to timeout recursive calls.
    var el = Nayad.safeGetElement( startConf );
  } else {
    if ( typeof(startConf.el) == "string" )
      startConf.el = Nayad.safeGetElement( startConf.el );
    var el = startConf.el;
  }
  if ( ! el.inkWebMoving ) {
    el.inkWebMoving = {
      step: 0
    };
  }
  var conf = el.inkWebMoving;
  if ( conf.step == 0 ) {
    conf.x = startConf.x;
    conf.y = startConf.y;
    // dur : duration of the animation in seconds
    if ( startConf.dur ) { conf.dur = startConf.dur }
    else { conf.dur = 1 }
    // steps : animation steps in a second
    if ( startConf.stepsBySec ) { conf.stepsBySec = startConf.stepsBySec }
    else { conf.stepsBySec = 16 }
    conf.sleep = Math.round( 1000 / conf.stepsBySec );
    conf.steps = conf.dur * conf.stepsBySec;
    var startPos = el.getBBox();
    conf.xInc = ( conf.x - startPos.x ) / conf.steps;
    conf.yInc = ( conf.y - startPos.y ) / conf.steps;
    conf.transform = el.transform.baseVal.consolidate();
    if ( ! conf.transform ) {
      conf.transform = el.ownerSVGElement.createSVGTransform();
    }
    el.transform.baseVal.clear();
    el.transform.baseVal.appendItem(conf.transform);
  }
  if ( conf.step < conf.steps ) {
    conf.step++;
    conf.transform.matrix.e += conf.xInc;
    conf.transform.matrix.f += conf.yInc;
    try{ el.ownerSVGElement.forceRedraw() }
    catch(e){ this.log(e, "this "+el.ownerSVGElement+" has no forceRedraw().") }
    conf.timeout = setTimeout( 'InkWeb.moveElTo("'+el.id+'")', conf.sleep );
  } else {
    delete el.inkWebMoving;
  }
}

InkWeb.log = function () { /* if you need that, use the inkweb-debug.js too */ }

/* nayad.js - Custom functionality for Nayad */
/*
**  InkWeb - Inkscape's Javscript features for the open vector web
**
**  Copyright (C) 2013 Buck Buchalter
**
*/



var Nayad = {

  version: 0.01,

  topBackLayers:  "suit-tops-back",
  topFrontLayers: "suit-tops-front vtrim-top spec-v-insert midriff",


  bottomBackLayers: "help spec-overtrim overtrim inside-skirt-accent spec-skortshort skort-short layer_shorts_4 layer_shorts_2 suit-skimpy suit-full trim-bottom-4 trim-bottom-2 v-trim-bottom skirt skirt-accent short-highlights w-banded-band bandedbottom",
  bottomFrontLayers: "spec-shorts-inseam layer_shorts_4 layer_shorts_2 overtrim"
};







// SET DEFAULTS

Nayad.showDefaults = function() {
  var default_top_front_image = Nayad.safeGetElement("g24166");
  Nayad.showTopFront(default_top_front_image);

  var default_top_back_image = Nayad.safeGetElement("g24176");
  Nayad.showTopBack(default_top_back_image);

  var default_bottom_image = Nayad.safeGetElement("g23392");
  Nayad.showBottoms(default_bottom_image);

 InkWeb.setAtt({el:['g6487'], att:'opacity', val:'0'});

};










/*
  HELPER FUNCTIONS
*/

Nayad.safeGetElement = function(element_id) {
  var el = document.getElementById( element_id );
  if (el == undefined) {
    alert("you asked me to find '" + element_id + "', but it doesn't exist in the DOM. Please check your code.");
  } else {
    return el;
  }
};




// MAIN SHOW FUNCTION
Nayad.showPathsForElement = function(element) {
  Nayad.setAttributeForElement(element, 'opacity', '1');
};


// MAIN HIDE FUNCTION
Nayad.hidePathsForElement = function(element) {
  Nayad.setAttributeForElement(element, 'opacity', '0');
};







Nayad.activateLayersForElement = function(element) {
  var active_layer_ids = element.attributes["active_layer_ids"];
  if(active_layer_ids != undefined) {
    var array_of_layer_ids = active_layer_ids.value.split(" ");
    for(var i = 0; i < array_of_layer_ids.length; i++) {

      var current_layer = Nayad.safeGetElement(array_of_layer_ids[i]);
      if(current_layer.parentNode != Nayad.getSVG()) {
        alert("You asked me to active element with id " +array_of_layer_ids[i]+ " but this function only supports elements whose DIRECT parent is the SVG.");
      } else {
         // MOVE THIS ELEMENT TO END OF SVG DOM
         Nayad.getSVG().appendChild(current_layer);
      }

    }
  };
};



Nayad.setAttributeForElement = function(element, attribute, value) {


   // GET BOTH LAYER IDS AND PATH IDS
   var layer_ids = element.attributes["layer_ids"];
   var path_ids = element.attributes["path_ids"];




  if(layer_ids == undefined && path_ids == undefined) {
    // CHECK IF EITHER ARE PRESENT, Warn user if they are not defined.
    alert("this image doesn't have a 'layer_ids' defined or a 'path_ids' defined!");
  }  


  if(layer_ids != undefined) {
   // CHECK IF LAYER IDS ARE PRESENT

    paths_array = Nayad.getPathIdsByLayerIds(layer_ids.value);

    // Use InkWeb to set the opacity to 1 for all paths
    // paths.value returns the string of the ids for each DOM element to set the attribute for
    InkWeb.setAtt({el:paths_array, att: attribute, val: value}); 
  }  



  if(path_ids != undefined) {
    // CHECK IF PATH IDS ARE PRESENT
    paths_array =path_ids.value.split( " " );
    InkWeb.setAtt({el:paths_array, att: attribute, val: value}); 
  }
};





// GET LAYERS AND PATHS FUNCTIONS

Nayad.getSVG = function() {
  return Nayad.safeGetElement("nayad_svg");
};

Nayad.getLayerById = function(layer_id) {
  return Nayad.getSVG().getElementById(layer_id);
};

Nayad.getPathsByLayerId = function(layer_id) {
  return Nayad.getLayerById(layer_id).getElementsByTagName("path");
};

Nayad.getPathIdsByLayerId = function(layer_id) {
  var layer_paths = Nayad.getPathsByLayerId(layer_id);
  var path_ids = [];

  for (var i = 0; i < layer_paths.length; i++) {
    path_ids.push( layer_paths[i]["id"] );
  }

  return path_ids;
}

Nayad.getPathIdsByLayerIds = function(layer_ids) {
  var layer_id_array = layer_ids.split(" ");

  var path_ids = [];

   for (var i = 0; i < layer_id_array.length; i++) {
    path_ids = path_ids.concat( Nayad.getPathIdsByLayerId(layer_id_array[i]) );
  }

  return path_ids;

};



/*

BOTTOMS

*/
Nayad.showBottoms = function(image) {
  Nayad.hideBottoms();
  Nayad.showPathsForElement(image);
  Nayad.activateLayersForElement(image);
};

Nayad.hideBottoms = function() {
  Nayad.hideBottomBack();
  Nayad.hideBottomFront();
}

Nayad.hideBottomBack = function() {

  var bottom_back_paths = Nayad.getPathIdsByLayerIds( Nayad.bottomBackLayers );

  InkWeb.setAtt({
    el: bottom_back_paths, 
    att: 'opacity', 
    val: '0'
  });
};

Nayad.hideBottomFront = function() {

  var bottom_front_paths = Nayad.getPathIdsByLayerIds( Nayad.bottomFrontLayers );

  InkWeb.setAtt({
    el: bottom_front_paths, 
    att: 'opacity', 
    val: '0'
  });
};








/*

  TOPS

*/


Nayad.hideTops = function() {
  Nayad.hideTopBack();
  Nayad.hideTopFront();
}

Nayad.hideTopBack = function() {

  var top_back_paths = Nayad.getPathIdsByLayerIds( Nayad.topBackLayers );

  InkWeb.setAtt({
    el: top_back_paths, 
    att: 'opacity', 
    val: '0'
  });
};

Nayad.hideTopFront = function() {

  var top_front_paths = Nayad.getPathIdsByLayerIds( Nayad.topFrontLayers );

  InkWeb.setAtt({
    el: top_front_paths, 
    att: 'opacity', 
    val: '0'
  });
};

Nayad.showTopBack = function(image) {
  Nayad.hideTopBack();
  Nayad.showPathsForElement(image);
};

Nayad.showTopFront = function(image) {
  Nayad.hideTopFront();
  Nayad.showPathsForElement(image);
};

Nayad.showMidriff = function(image) {
  Nayad.showPathsForElement(image);
};

Nayad.showVinsert = function(image) {
  Nayad.showPathsForElement(image);
};

Nayad.showHelp = function(image) {
  Nayad.showPathsForElement(image);
};

Nayad.hideHelp = function(image) {
  Nayad.hidePathsForElement(image);
};

Nayad.hideMidriff = function(image) {
  Nayad.hidePathsForElement(image);
};

/*

  PATTERNS

*/

Nayad.fillPattern = function(rect) {

  var paths = rect.attributes['path_ids'];

  if(paths == undefined) {
    alert("this pattern doesn't have a path defined, please use 'path_ids'!");
  } else {

    // It seems InkWeb.transmitAtt wants an array
    // but we are only able to store strings inside the DOM attributes
    // so we split the string into an array based on the space delimiter
    paths_array = paths.value.split(" ");

    InkWeb.transmitAtt({
    from: rect, 
    to: paths_array, 
    att: 'fill'
  });
  }
};
